#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//vUv = vUvOriginal;
ret.z = GetPixel(vUv).z*0.5;

   float pixelDistance   = 4;
   float motionStrength  = 4;

   float diffusionFactor = 1;
   float decay           = -0.014;

   vec2 uv_y = mix(vUvOriginal,vUv,0);
   vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw*diffusionFactor;

   vec2 d = uTexSize.zw*pixelDistance;
   float1 dx = ( 2*GetBlur1(uv_y + vec2(1,0)*d) - 2*GetBlur1(uv_y-vec2(1,0)*d) ).y*0.5;
   float1 dy = ( 2*GetBlur1(uv_y + vec2(0,1)*d) - 2*GetBlur1(uv_y-vec2(0,1)*d) ).y*0.5;

   vec2 my_uv = uv_y + vec2(dx,dy)*uTexSize.zw*motionStrength;

   ret.y = texture( sampler_fw_main, clamp01(my_uv)).y;

   ret.y += (ret - GetBlur1(uv_y)).y*0.025 + decay;


   ret.y += (texture(sampler_noise_lq, dither_uv).y-0.5)*0.02;

   dx = ( 2*GetBlur1(uv_y + vec2(1,0)*d) - 2*GetBlur1(uv_y-vec2(1,0)*d) ).x*0.5;
   dy = ( 2*GetBlur1(uv_y + vec2(0,1)*d) - 2*GetBlur1(uv_y-vec2(0,1)*d) ).x*0.5;

   my_uv = vUv - vec2(dx,dy)*uTexSize.zw*motionStrength;

ret.x = GetPixel(my_uv).x - ret.y*0.01 + 0.004;
ret.x += (texture(sampler_noise_lq, dither_uv).x-0.5)*0.01 + ret.z*0.14;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


 float zoom =1.81;
 vec2 c = vec2(0.448+q9,0.701+q10);
 vec2 my_uv2 = (vUv-0.5)*zoom;
 my_uv2 = vec2(my_uv2.x*my_uv2.x - my_uv2.y*my_uv2.y, 2*my_uv2.x*my_uv2.y) + c;
 my_uv2 = 1.0 - abs( fract( my_uv2 * 0.5 ) * 2.0 - 1.0 ); // Eo.S' mirror code

 float julia = GetPixel(my_uv2).z;

    d = uTexSize.zw*3;
    dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
    dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

vec3 base = GetPixel(vUv);
vec3 emboss = (-dx + dy + 1)*1.4;
float grad_x = length(vec2(dx.x,dy.x));
float grad_y = length(vec2(dx.y,dy.y));


ret = mix( vec3(0.6,0.5,0.4)*base.x*emboss.x,
            vec3(4,2,1)*grad_x,
            grad_x*2
          );


ret = mix(ret, vec3(0.3,0,0), julia*4);
ret = mix(ret, vec3(0,0,1.4), grad_y*1.4);
ret = mix(ret, 0.5, base.y*2);

  fragColor = ret;
}
